import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Java auf Windows installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Java auf Windows.","frontmatter":{"title":"Java auf Windows installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Java auf Windows.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"de_de/1.20.4/players/installing-java/windows.md","filePath":"versions/1.20.4/translated/de_de/players/installing-java/windows.md","lastUpdated":1739538073000}`);var l={name:`de_de/1.20.4/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Java auf Windows installieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Java auf Windows installieren”">​</a></h1><p>Diese Anleitung führt Sie durch die Installation von Java 17 auf Windows.</p><p>Der Minecraft Launcher kommt bereits mit seiner eigenen Java Installation, diese Sektion ist also nur relevant, wenn Sie den Fabric <code>.jar</code> basierten Installer verwenden möchten oder wenn Sie die Minecraft Server <code>.jar</code> verwenden möchten.</p><h2 id="_1-uberprufen-ob-java-bereits-installiert-ist" tabindex="-1">1. Überprüfen, ob Java bereits installiert ist <a class="header-anchor" href="#_1-uberprufen-ob-java-bereits-installiert-ist" aria-label="Permalink to “1. Überprüfen, ob Java bereits installiert ist”">​</a></h2><p>Um zu überprüfen, ob Java bereits installiert ist, öffnen Sie die Kommandozeile.</p><p>Drücken Sie <kbd>Win</kbd>+<kbd>R</kbd> und geben Sie <code>cmd.exe</code> in das Feld ein.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Windows-Ausführungsdialog mit &quot;cmd.exe&quot; in der Ausführungsleiste" loading="lazy"></p><p>Wenn Sie die Kommandozeile geöffnet haben, geben Sie <code>java -version</code> ein und drücken <kbd>Enter</kbd>.</p><p>Wenn der Befehl erfolgreich ausgeführt wird, sollten Sie folgendes sehen. Wenn der Befehl fehlgeschlagen ist, fahren Sie mit dem nächsten Schritt fort.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Kommandozeile mit &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Um den Großteil der modernen Minecraft-Versionen nutzen zu können, musst du Java 17 installiert haben. Wenn der Befehl eine Version niedriger als 17 anzeigt, musst du deine bestehende Java-Installation aktualisieren.</p></div><h2 id="_2-herunterladen-des-java-17-installer" tabindex="-1">2. Herunterladen des Java 17 Installer <a class="header-anchor" href="#_2-herunterladen-des-java-17-installer" aria-label="Permalink to “2. Herunterladen des Java 17 Installer”">​</a></h2><p>Um Java 17 zu installieren, laden Sie bitte den Installer von <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=17" target="_blank" rel="noreferrer">Adoptium</a> herunter.</p><p>Sie müssen die Version &quot;Windows Installer (.msi)&quot; herunterladen:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium Download-Seite mit hervorgehobenem Windows Installer (.msi)" loading="lazy"></p><p>Sie sollten <code>x86</code> wählen, wenn Sie ein 32-Bit-Betriebssystem haben, oder <code>x64</code>, wenn Sie ein 64-Bit-Betriebssystem haben.</p><p>Die meisten modernen Computer sind mit einem 64-Bit-Betriebssystem ausgestattet. Wenn Sie sich unsicher sind, versuchen Sie es mit dem 64-Bit-Download.</p><h2 id="_3-installer-starten" tabindex="-1">3. Installer starten! <a class="header-anchor" href="#_3-installer-starten" aria-label="Permalink to “3. Installer starten!”">​</a></h2><p>Folgen Sie den Schritten des Installationsprogramms, um Java 17 zu installieren. Wenn Sie diese Seite erreichen, sollten Sie die folgenden Funktionen auf &quot;Die gesamte Funktion wird auf der lokalen Festplatte installiert&quot; einstellen:</p><ul><li><code>JAVA_HOME Umgebungsvariable setzen</code> - Diese wird zu Ihrem PATH hinzugefügt.</li><li>JavaSoft (Oracle)-Registrierungsschlüssel</li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Java 17-Installationsprogramm mit &quot;JAVA_HOME-Variable setzen&quot; und &quot;JavaSoft (Oracle) Registrierungsschlüssel&quot; hervorgehoben" loading="lazy"></p><p>Wenn Sie das getan haben, können Sie <code>Weiter</code> klicken und mit der Installation fortfahren.</p><h2 id="_4-verifizieren-dass-java-17-installiert-ist" tabindex="-1">4. Verifizieren, dass Java 17 installiert ist <a class="header-anchor" href="#_4-verifizieren-dass-java-17-installiert-ist" aria-label="Permalink to “4. Verifizieren, dass Java 17 installiert ist”">​</a></h2><p>Sobald die Installation abgeschlossen ist, können Sie überprüfen, ob Java 17 installiert ist, indem Sie die Kommandozeile erneut öffnen und &quot;java -version&quot; eingeben.</p><p>Wenn der Befehl erfolgreich ausgeführt wird, wird die Java-Version wie zuvor gezeigt angezeigt:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Kommandozeile mit &quot;java -version&quot;" loading="lazy"></p><p>Sollten Sie auf Probleme stoßen, können Sie im <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> im Channel <code>#player-support</code> um Hilfe bitten.</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};